#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 205;
const int K = 3005;
struct State{
    int pip;//匹配情况
    int hox;//后缀小于 s
    int sml;//字典序小于 s
    bool has;//含不含 s
    char lst;//上一个字符
};
int T,n,k;
int nxt[N],dep[N];
int mth[N][2],cnt1[N][2];
string s,Ans;
queue<State> q;
State f[N][85][K][2],Ed;
bool vis[N][85][K][2],Can;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    T=read(),T=read();
    while(T--){
        n=read(),k=read();
        cin>>s;s=" "+s+" ";
        //读入

        nxt[1]=0,dep[1]=(n!=1);
        for(int i=2,j=0;i<=n;i++){
            while(j&&s[j+1]!=s[i])j=nxt[j];
            if(s[j+1]==s[i])++j;
            nxt[i]=j,dep[i]=dep[j]+(i!=n);
        }//预处理 nxt 数组和 dep 数组

        for(int i=0;i<=n;i++)
            for(int c=0;c<=1;c++){
                int j=i;
                while(j&&s[j+1]!=c+'0')j=nxt[j];
                if(s[j+1]==c+'0')++j;
                mth[i][c]=j;
                j=i;int c1=0;
                while(j)c1+=(s[j+1]=='1'),j=nxt[j];
                cnt1[i][c]=c1+(s[1]=='1');
            }
        //预处理 mth 和 cnt1 方便后续转移

        memset(vis,0,sizeof(vis));
        f[0][0][0][0]={0,0,0,0,0};
        vis[0][0][0][0]=1;
        while(!q.empty())q.pop();
        q.push({0,0,0,0,0});Can=0;
        //初始化准备 BFS

        while(!q.empty()){
            auto [p,h,sm,flg,cc]=q.front();q.pop();
            if(flg&&sm==k){Can=1,Ed={p,h,sm,flg,cc};break;}
            for(int ad=0;ad<=1;ad++){
                int np=mth[p][ad];
                int nh=h+(ad==0)*cnt1[p][ad];
                int nsm=sm+dep[np]+nh;
                bool ng=flg|(np==n);
                if(nsm>k||vis[np][nh][nsm][ng])continue;
                vis[np][nh][nsm][ng]=1;
                f[np][nh][nsm][ng]={p,h,sm,flg,ad};
                q.push({np,nh,nsm,ng,ad});
            }
        }//BFS 寻找长度最短的摩卡串

        if(!Can){cout<<"Impossible\n";continue;}
        //如果一直没搜到表示无解

        auto [p,h,sm,flg,cc]=Ed;Ans="";
        while(p||h||sm||flg){
            auto [np,nh,nsm,ng,nc]=f[p][h][sm][flg];
            Ans=(char)(nc+'0')+Ans;p=np,h=nh,sm=nsm,flg=ng;
        }//利用 BFS 时存下来的信息不断回溯得到答案

        cout<<Ans<<"\n";
        //输出
    }
    return 0;
}
